  1→import { randomUUID } from "node:crypto";
  2→import { RecordId } from "surrealdb";
  3→import { z } from "zod";
  4→import type { BranchConversationResponse } from "../../shared/contracts";
  5→import type { ConversationRow } from "../extraction/types";
  6→import { HttpError } from "../http/errors";
  7→import { logError, logInfo, logWarn } from "../http/observability";
  8→import { jsonError, jsonResponse } from "../http/response";
  9→import { resolveWorkspaceRecord } from "../workspace/workspace-scope";
 10→import { deriveMessageTitle } from "../workspace/conversation-sidebar";
 11→import type { ServerDependencies } from "../runtime/types";
 12→
 13→const branchRequestSchema = z.object({
 14→  messageId: z.string().min(1),
 15→});
 16→
 17→export function createBranchConversationHandler(
 18→  deps: ServerDependencies,
 19→): (workspaceId: string, parentConversationId: string, request: Request) => Promise<Response> {
 20→  return (workspaceId: string, parentConversationId: string, request: Request) =>
 21→    handleBranchConversation(deps, workspaceId, parentConversationId, request);
 22→}
 23→
 24→async function handleBranchConversation(
 25→  deps: ServerDependencies,
 26→  workspaceId: string,
 27→  parentConversationId: string,
 28→  request: Request,
 29→): Promise<Response> {
 30→  let body: unknown;
 31→  try {
 32→    body = await request.json();
 33→  } catch {
 34→    return jsonError("invalid JSON body", 400);
 35→  }
 36→
 37→  const parsed = branchRequestSchema.safeParse(body);
 38→  if (!parsed.success) {
 39→    return jsonError(`invalid branch request: ${parsed.error.message}`, 400);
 40→  }
 41→
 42→  let workspaceRecord: RecordId<"workspace", string>;
 43→  try {
 44→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 45→  } catch (error) {
 46→    if (error instanceof HttpError) {
 47→      return jsonError(error.message, error.status);
 48→    }
 49→    logError("branch.workspace_resolve.failed", "Failed to resolve workspace", error, { workspaceId });
 50→    return jsonError("failed to resolve workspace", 500);
 51→  }
 52→
 53→  try {
 54→    const parentRecord = new RecordId("conversation", parentConversationId);
 55→    const parent = await deps.surreal.select<ConversationRow>(parentRecord);
 56→    if (!parent) {
 57→      throw new HttpError(404, `conversation not found: ${parentConversationId}`);
 58→    }
 59→
 60→    if ((parent.workspace.id as string) !== (workspaceRecord.id as string)) {
 61→      throw new HttpError(400, "conversation does not belong to workspace");
 62→    }
 63→
 64→    // Validate branch point message belongs to the parent conversation
 65→    const branchPointMessageRecord = new RecordId("message", parsed.data.messageId);
 66→    const [msgRows] = await deps.surreal
 67→      .query<[Array<{ id: RecordId<"message", string> }>]>(
 68→        "SELECT id FROM message WHERE id = $msg AND conversation = $parent LIMIT 1;",
 69→        { msg: branchPointMessageRecord, parent: parentRecord },
 70→      )
 71→      .collect<[Array<{ id: RecordId<"message", string> }>]>();
 72→
 73→    if (msgRows.length === 0) {
 74→      throw new HttpError(400, "message does not belong to parent conversation");
 75→    }
 76→
 77→    const now = new Date();
 78→    const branchId = randomUUID();
 79→    const branchRecord = new RecordId("conversation", branchId);
 80→    const edgeRecord = new RecordId("branched_from", randomUUID());
 81→
 82→    const branchTitle = parent.title
 83→      ? deriveMessageTitle(`Branch of: ${parent.title}`)
 84→      : "Branch";
 85→
 86→    const transaction = await deps.surreal.beginTransaction();
 87→    try {
 88→      await transaction.create(branchRecord).content({
 89→        createdAt: now,
 90→        updatedAt: now,
 91→        workspace: workspaceRecord,
 92→        title: branchTitle,
 93→        title_source: "message",
 94→      });
 95→
 96→      await transaction
 97→        .relate(branchRecord, edgeRecord, parentRecord, {
 98→          branched_at: now,
 99→          branch_point_message: branchPointMessageRecord,
100→        })
101→        .output("after");
102→
103→      await transaction.commit();
104→    } catch (error) {
105→      await transaction.cancel();
106→      throw error;
107→    }
108→
109→    logInfo("branch.created", "Conversation branch created", {
110→      workspaceId,
111→      parentConversationId,
112→      branchId,
113→      branchPointMessageId: parsed.data.messageId,
114→    });
115→
116→    const response: BranchConversationResponse = {
117→      conversationId: branchId,
118→      parentConversationId,
119→      branchPointMessageId: parsed.data.messageId,
120→    };
121→
122→    return jsonResponse(response, 201);
123→  } catch (error) {
124→    if (error instanceof HttpError) {
125→      logWarn("branch.http_error", "Branch creation failed with client-facing error", {
126→        workspaceId,
127→        parentConversationId,
128→        statusCode: error.status,
129→      });
130→      return jsonError(error.message, error.status);
131→    }
132→
133→    logError("branch.failed", "Branch creation failed", error, {
134→      workspaceId,
135→      parentConversationId,
136→    });
137→    const message = error instanceof Error ? error.message : "branch creation failed";
138→    return jsonError(message, 500);
139→  }
140→}
141→

  1→import { RecordId, type Surreal } from "surrealdb";
  2→
  3→export type BranchLink = {
  4→  conversationId: string;
  5→  parentConversationId: string;
  6→  branchPointMessageId: string;
  7→  branchPointCreatedAt: Date;
  8→};
  9→
 10→export type InheritableMessage = {
 11→  id: string;
 12→  role: "user" | "assistant";
 13→  text: string;
 14→  createdAt: Date | string;
 15→  suggestions?: string[];
 16→  inherited: boolean;
 17→};
 18→
 19→type MessageRow = {
 20→  id: RecordId<"message", string>;
 21→  role: "user" | "assistant";
 22→  text: string;
 23→  createdAt: Date | string;
 24→  suggestions?: string[];
 25→};
 26→
 27→/**
 28→ * Walk branched_from edges from a conversation up to the root.
 29→ * Returns an ordered array (root-first) of branch links.
 30→ */
 31→export async function loadBranchChain(
 32→  surreal: Surreal,
 33→  conversationId: string,
 34→): Promise<BranchLink[]> {
 35→  const chain: BranchLink[] = [];
 36→  let current = conversationId;
 37→
 38→  for (let depth = 0; depth < 10; depth++) {
 39→    const conversationRecord = new RecordId("conversation", current);
 40→    const [rows] = await surreal
 41→      .query<[Array<{
 42→        out: RecordId<"conversation", string>;
 43→        branch_point_message: RecordId<"message", string>;
 44→      }>]>(
 45→        "SELECT out, branch_point_message FROM branched_from WHERE `in` = $conversation LIMIT 1;",
 46→        { conversation: conversationRecord },
 47→      )
 48→      .collect<[Array<{
 49→        out: RecordId<"conversation", string>;
 50→        branch_point_message: RecordId<"message", string>;
 51→      }>]>();
 52→
 53→    if (rows.length === 0) break;
 54→
 55→    const edge = rows[0];
 56→    const branchPointMsg = await surreal.select<{ createdAt: Date | string }>(edge.branch_point_message);
 57→    if (!branchPointMsg) {
 58→      throw new Error(`branch point message not found: ${edge.branch_point_message.id as string}`);
 59→    }
 60→
 61→    chain.unshift({
 62→      conversationId: current,
 63→      parentConversationId: edge.out.id as string,
 64→      branchPointMessageId: edge.branch_point_message.id as string,
 65→      branchPointCreatedAt: branchPointMsg.createdAt instanceof Date
 66→        ? branchPointMsg.createdAt
 67→        : new Date(branchPointMsg.createdAt),
 68→    });
 69→
 70→    current = edge.out.id as string;
 71→  }
 72→
 73→  return chain;
 74→}
 75→
 76→/**
 77→ * Load all messages for a conversation including inherited messages from ancestor branches.
 78→ * Inherited messages are marked with `inherited: true`.
 79→ */
 80→export async function loadMessagesWithInheritance(
 81→  surreal: Surreal,
 82→  conversationId: string,
 83→  limit: number,
 84→): Promise<InheritableMessage[]> {
 85→  const chain = await loadBranchChain(surreal, conversationId);
 86→
 87→  if (chain.length === 0) {
 88→    const messages = await queryConversationMessages(surreal, conversationId, limit);
 89→    return messages.map((m) => toInheritable(m, false));
 90→  }
 91→
 92→  const allMessages: InheritableMessage[] = [];
 93→
 94→  // Root conversation messages up to first branch point
 95→  const rootConvId = chain[0].parentConversationId;
 96→  const rootMessages = await queryMessagesUpToBranchPoint(
 97→    surreal,
 98→    rootConvId,
 99→    chain[0].branchPointCreatedAt,
100→  );
101→  allMessages.push(...rootMessages.map((m) => toInheritable(m, true)));
102→
103→  // Intermediate ancestor messages between branch points
104→  for (let i = 0; i < chain.length - 1; i++) {
105→    const intermediateMessages = await queryMessagesUpToBranchPoint(
106→      surreal,
107→      chain[i].conversationId,
108→      chain[i + 1].branchPointCreatedAt,
109→    );
110→    allMessages.push(...intermediateMessages.map((m) => toInheritable(m, true)));
111→  }
112→
113→  // Current conversation's own messages
114→  const ownMessages = await queryConversationMessages(surreal, conversationId, limit);
115→  allMessages.push(...ownMessages.map((m) => toInheritable(m, false)));
116→
117→  return allMessages;
118→}
119→
120→function toInheritable(row: MessageRow, inherited: boolean): InheritableMessage {
121→  return {
122→    id: row.id.id as string,
123→    role: row.role,
124→    text: row.text,
125→    createdAt: row.createdAt,
126→    ...(row.suggestions && row.suggestions.length > 0 ? { suggestions: row.suggestions } : {}),
127→    inherited,
128→  };
129→}
130→
131→async function queryConversationMessages(
132→  surreal: Surreal,
133→  conversationId: string,
134→  limit: number,
135→): Promise<MessageRow[]> {
136→  const conversationRecord = new RecordId("conversation", conversationId);
137→  const [rows] = await surreal
138→    .query<[MessageRow[]]>(
139→      "SELECT id, role, text, createdAt, suggestions FROM message WHERE conversation = $conversation ORDER BY createdAt ASC LIMIT $limit;",
140→      { conversation: conversationRecord, limit },
141→    )
142→    .collect<[MessageRow[]]>();
143→  return rows;
144→}
145→
146→/**
147→ * Load messages from a conversation up to and including the branch point message
148→ * and its assistant response (the next message after the branch point).
149→ */
150→async function queryMessagesUpToBranchPoint(
151→  surreal: Surreal,
152→  conversationId: string,
153→  branchPointCreatedAt: Date,
154→): Promise<MessageRow[]> {
155→  const conversationRecord = new RecordId("conversation", conversationId);
156→
157→  // Find the assistant response following the branch point (if any)
158→  const [nextRows] = await surreal
159→    .query<[MessageRow[]]>(
160→      "SELECT id, role, text, createdAt, suggestions FROM message WHERE conversation = $conversation AND createdAt > $branchPointAt ORDER BY createdAt ASC LIMIT 1;",
161→      { conversation: conversationRecord, branchPointAt: branchPointCreatedAt },
162→    )
163→    .collect<[MessageRow[]]>();
164→
165→  const cutoffAt = nextRows.length > 0 && nextRows[0].role === "assistant"
166→    ? (nextRows[0].createdAt instanceof Date ? nextRows[0].createdAt : new Date(nextRows[0].createdAt as string))
167→    : branchPointCreatedAt;
168→
169→  const [rows] = await surreal
170→    .query<[MessageRow[]]>(
171→      "SELECT id, role, text, createdAt, suggestions FROM message WHERE conversation = $conversation AND createdAt <= $cutoff ORDER BY createdAt ASC;",
172→      { conversation: conversationRecord, cutoff: cutoffAt },
173→    )
174→    .collect<[MessageRow[]]>();
175→
176→  return rows;
177→}
