  position: relative;
  margin: 2px auto 8px 0;
  padding: 4px;
  color: var(--muted-foreground, #888);
  background: transparent;
  border: 1px solid transparent;
  border-radius: 0;
  cursor: pointer;
  opacity: 0.5;
  transition: opacity 0.15s, background 0.15s, border-color 0.15s;
}

.branch-message-btn:hover {
  opacity: 1 !important;
  background: var(--accent, #f0f0f0);
  border-color: var(--border, #d0d0d0);
}

.branch-message-btn:disabled {
  cursor: not-allowed;
  opacity: 0.2 !important;
}

.branch-message-tooltip {
  visibility: hidden;
  position: absolute;
  left: 100%;
  top: 50%;
  transform: translateY(-50%);
  margin-left: 6px;
  padding: 4px 8px;
  font-size: 0.72rem;
  white-space: nowrap;
